"""
Implementing Binary Search Tree Data Structure using Python
A binary search tree (BST) is a data structure that stores sorted data efficiently. It allows fast insertion, deletion, and searching operations. In this implementation, we use classes to define the node and tree structures. We also provide methods to insert, delete, and search nodes in the tree.
"""


class Node:
    """
    A node represents a single element in a binary search tree. Each node has a value, a reference to the left child, and a reference to the right child.
    """

    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None


class BinarySearchTree:
    """
    A binary search tree is a data structure where each node contains a value and references to its left and right children. The tree maintains the invariant that all values in the left subtree are less than or equal to the parent's value, and all values in the right subtree are greater than the parent's value.
    """

    def __init__(self):
        self.root = None

    def insert(self, val):
        """
        Insert a new value into the binary search tree. If the tree is empty, create a new root node containing the value. Otherwise, traverse the tree recursively to find the appropriate position for the new node.
        """
        if not self.root:
            self.root = Node(val)
        else:
            self._insert_recursive(val, self.root)

    def _insert_recursive(self, val, curr):
        if val < curr.val:
            if curr.left is None:
                curr.left = Node(val)
            else:
                self._insert_recursive(val, curr.left)
        elif val > curr.val:
            if curr.right is None:
                curr.right = Node(val)
            else:
                self._insert_recursive(val, curr.right)
        else:
            raise ValueError("Duplicate Value!")

    def search(self, val):
        """
        Search for a specific value in the binary search tree. Start from the root node and compare the value against the current node's value. If the value is smaller, move to the left child, otherwise move to the right child. Repeat this process until the value is found or there are no more children to explore.
