import java.util.Arrays;
import java.util.List;
import java.util.Map;
import java.util.function.Function;
import java.util.stream.Collectors;

class Solution {
  public List<Integer> findAnagrams(String s, String p) {
    Map<Character, Integer> freqs = getFrequencyMap(p);
    int left = 0;
    int right = 0;
    int matchedCount = 0;
    List<Integer> indices = Arrays.asList();
    while (right < s.length()) {
      Character currChar = s.charAt(right);
      if (freqs.containsKey(currChar)) {
        freqs.put(currChar, freqs.get(currChar) - 1);
        if (freqs.get(currChar) == 0) {
          matchedCount++;
        }
      }
      right++;
      while (matchedCount == freqs.size()) {
        if (right - left == p.length()) {
          indices.add(left);
        }
        Character leftChar = s.charAt(left);
        if (freqs.containsKey(leftChar)) {
          freqs.put(leftChar, freqs.get(leftChar) + 1);
          if (freqs.get(leftChar) > 0) {
            matchedCount--;
          }
        }
        left++;
      }
    }
    return indices;
  }

  private Map<Character, Integer> getFrequencyMap(String pattern) {
    return pattern.chars().mapToObj(c -> (char) c).collect(Collectors.groupingBy(Function.identity(), Collectors.counting()));
  }
}

